import ClientLogos from "../../animations/ClientLogos";
import ClientLogosReverse from "../../animations/ClientLogosReverse";
import Logo from "../../assets/favicon.svg";

const LogoSlider = () => {
  return (
    <>
      <div
        id="clients"
        className="w-full px-4 sm:px-6 lg:px-10 max-w-[1440px] mx-auto py-10 sm:py-12 lg:py-14"
      >
        <h1 className="text-center text-[20px] sm:text-[24px] md:text-[28px] lg:text-[30px] xl:text-[36px] font-bold leading-tight max-w-[90%] sm:max-w-[600px] mx-auto mb-8">
          Empowering businesses with reliable ERP
        </h1>

        <div className="relative flex justify-center items-center overflow-hidden">
          {/* Reverse sliding logos */}
          <ClientLogosReverse />

          {/* Center circle logo */}
          <div className="absolute z-10 w-16 h-full flex justify-center items-center bg-black bg-opacity-80 shadow-[0_0_30px_0px_rgba(0,0,0,1)]">
            <div className="relative w-14 h-14 sm:w-16 sm:h-16 md:w-20 md:h-20 flex justify-center items-center bg-black rounded-full backdrop-blur-lg shadow-[0_0_30px_0px_rgba(255,255,255,0.4)]">
              <div className="absolute z-20 w-full h-full p-2 bg-black rounded-full shadow-[0_0_17px_0px_rgba(163,230,53.1)]">
                <img
                  src={Logo}
                  className="w-full h-full object-contain"
                  alt="logo"
                />
              </div>
            </div>
          </div>

          {/* Forward sliding logos */}
          <ClientLogos />
        </div>
      </div>
    </>
  );
};

export default LogoSlider;
